import{c as a,Q as t,j as r,m as i}from"./chunks/framework.BXc4yaFE.js";const h=JSON.parse('{"title":"HARBOR: Automated Harness Optimization","description":"","frontmatter":{"title":"HARBOR: Automated Harness Optimization","authors":"Biswa Sengupta, Jinhua Wang","published":"2026-04-22T00:00:00.000Z","source":"https://arxiv.org/abs/2604.20938"},"headers":[],"relativePath":"research/agent-harness/references/2026-04-22-harbor-automated-harness-optimization-2604-20938.md","filePath":"research/agent-harness/references/2026-04-22-harbor-automated-harness-optimization-2604-20938.md","lastUpdated":1779901665000}'),o={name:"research/agent-harness/references/2026-04-22-harbor-automated-harness-optimization-2604-20938.md"};function s(n,e,l,c,d,p){return t(),r("div",null,[...e[0]||(e[0]=[i(`<h1 id="harbor-automated-harness-optimization" tabindex="-1">HARBOR: Automated Harness Optimization <a class="header-anchor" href="#harbor-automated-harness-optimization" aria-label="Permalink to &quot;HARBOR: Automated Harness Optimization&quot;">​</a></h1><p><strong>Authors</strong>: Biswa Sengupta, Jinhua Wang <strong>Published</strong>: April 22, 2026 <strong>Source</strong>: <a href="https://arxiv.org/abs/2604.20938" target="_blank" rel="noreferrer">https://arxiv.org/abs/2604.20938</a><strong>arXiv ID</strong>: 2604.20938 <strong>Categories</strong>: cs.LG, cs.AI <strong>Benchmark</strong>: Terminal-Bench 2.0 (89 tasks)</p><hr><h2 id="abstract" tabindex="-1">Abstract <a class="header-anchor" href="#abstract" aria-label="Permalink to &quot;Abstract&quot;">​</a></h2><p>Long-horizon LLM agents are dominated not by their underlying model but by the harness that wraps it (~98.4% of Claude Code&#39;s codebase is deterministic harness code). HARBOR formalizes <strong>Automated Harness Optimization (AHO)</strong> as a constrained Bayesian optimization problem and provides a reference solver with cold-start correction, cost-aware acquisition, and safety constraints.</p><hr><h2 id="problem-formulation" tabindex="-1">Problem Formulation <a class="header-anchor" href="#problem-formulation" aria-label="Permalink to &quot;Problem Formulation&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>maximize: μ(c) = E_t[R(c,t)]</span></span>
<span class="line"><span>subject to: E_t[cost(c,t)] ≤ B_dep</span></span>
<span class="line"><span>            μ(c) ≥ R_0 - δ</span></span></code></pre></div><p>Where <code>c</code> is a configuration from a mixed Boolean/categorical/numeric space, <code>R(c,t)</code> is Bernoulli task outcome, constraints enforce cost budgets and safety margins.</p><hr><h2 id="motivation-manual-tuning-failure" tabindex="-1">Motivation: Manual Tuning Failure <a class="header-anchor" href="#motivation-manual-tuning-failure" aria-label="Permalink to &quot;Motivation: Manual Tuning Failure&quot;">​</a></h2><p>Four rounds of human-guided harness enhancement on Terminal-Bench 2 (all-flags-off baseline: 15/89):</p><table tabindex="0"><thead><tr><th>Round</th><th>Result</th><th>Cause</th></tr></thead><tbody><tr><td>B</td><td>+2 passes (15→17) ✓</td><td>Clean improvement</td></tr><tr><td>C</td><td>-4 passes (17→13) ✗</td><td>Low-capability self-evaluators</td></tr><tr><td>D</td><td>-5 passes (12/89) ✗</td><td>ACON cache corruption + integration bugs</td></tr></tbody></table><p><strong>Oracle (union of all flags)</strong>: 81/89 — massive headroom unreachable via manual tuning.</p><hr><h2 id="three-structural-properties" tabindex="-1">Three Structural Properties <a class="header-anchor" href="#three-structural-properties" aria-label="Permalink to &quot;Three Structural Properties&quot;">​</a></h2><h3 id="property-i-—-cold-start-correction" tabindex="-1">Property I — Cold-Start Correction <a class="header-anchor" href="#property-i-—-cold-start-correction" aria-label="Permalink to &quot;Property I — Cold-Start Correction&quot;">​</a></h3><p>Cross-session features (memory, compression) suffer from empty state in task-independent benchmarks. Mixture model:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>E[R(c,t)|n] = w(c,n)·p_∞(c) + (1-w(c,n))·p_base</span></span></code></pre></div><h3 id="property-ii-—-block-additive-surrogate" tabindex="-1">Property II — Block-Additive Surrogate <a class="header-anchor" href="#property-ii-—-block-additive-surrogate" aria-label="Permalink to &quot;Property II — Block-Additive Surrogate&quot;">​</a></h3><p>Sparse Axis-aligned Subspace (SAAS) prior with per-layer kernels + controlled cross-layer interactions. Handles ~40 nominal dimensions while exploiting sparsity via axis-aligned contraction.</p><h3 id="property-iii-—-multi-fidelity-cost-aware-acquisition" tabindex="-1">Property III — Multi-Fidelity Cost-Aware Acquisition <a class="header-anchor" href="#property-iii-—-multi-fidelity-cost-aware-acquisition" aria-label="Permalink to &quot;Property III — Multi-Fidelity Cost-Aware Acquisition&quot;">​</a></h3><p>Task subsets at m∈{8, 22, 44, 89} enable cheap early exploration:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>maximize: qNEHVI_m(c_{1:q}) / Cost(c_{1:q}, m)</span></span></code></pre></div><p>Information-per-dollar efficiency over standard acquisition.</p><hr><h2 id="harbor-algorithm" tabindex="-1">HARBOR Algorithm <a class="header-anchor" href="#harbor-algorithm" aria-label="Permalink to &quot;HARBOR Algorithm&quot;">​</a></h2><ol><li>Initialize with SAAS-prior GP on mixed-variable block-additive kernel</li><li>Place M trust regions via TuRBO at top incumbents</li><li>Loop while search budget permits: <ul><li>Select batch maximizing cost-normalized qNEHVI</li><li>Apply per-candidate safety constraint: lower credible bound ≥ R_0 - δ</li><li>Invert warm-start mixture model + attach heteroscedastic variance</li><li>Refit with NUTS sampling; update trust regions</li><li>Freeze silent dimensions after n_min observations</li></ul></li></ol><p><strong>Key innovation</strong>: Posterior chance constraint structurally prevents C-style regressions by rejecting candidates whose lower credible bound violates the safety margin.</p><hr><h2 id="harness-configuration-space" tabindex="-1">Harness Configuration Space <a class="header-anchor" href="#harness-configuration-space" aria-label="Permalink to &quot;Harness Configuration Space&quot;">​</a></h2><p><strong>Agent</strong>: codex-py (52K Python LOC) with gpt-5.4-nano</p><p><strong>9 flag-gated extensions</strong>:</p><ul><li>Native flags (5): semantic cache, cross-session memory, tiered compression, trajectory replay, speculative prediction</li><li>Published-technique flags (4): Reflexion, ACON, PASTE, self-evaluation gate</li></ul><p><strong>Telemetry counters</strong>: cache_hits, token_savings, reflections_written, reflections_retrieved, predictions_fired — enables silent bug detection via read/write asymmetry.</p><hr><h2 id="results" tabindex="-1">Results <a class="header-anchor" href="#results" aria-label="Permalink to &quot;Results&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Configuration</th><th>Passes / 89</th><th>%</th></tr></thead><tbody><tr><td>All-flags-off baseline</td><td>15</td><td>16.85%</td></tr><tr><td>Manual Round B (peak)</td><td>17</td><td>19.10%</td></tr><tr><td>Manual Round D (all-on)</td><td>12</td><td>13.48%</td></tr><tr><td><strong>HARBOR (~3.5 budget)</strong></td><td><strong>17</strong></td><td><strong>19.10%</strong></td></tr></tbody></table><ul><li>HARBOR matched manual peak using <strong>2 flags instead of 8</strong></li><li>Against Round D: +5 passes (+37% relative improvement)</li><li>Mean across 5 full-suite evaluations: 16.6/89 (18.65%)</li></ul><p><strong>HARBOR selected</strong>: cross-session memory + tiered compression only. Correctly disabled self-eval gate, ACON, Reflexion, PASTE.</p><hr><h2 id="critical-discoveries" tabindex="-1">Critical Discoveries <a class="header-anchor" href="#critical-discoveries" aria-label="Permalink to &quot;Critical Discoveries&quot;">​</a></h2><h3 id="_1-integration-bugs-as-signal" tabindex="-1">1. Integration Bugs as Signal <a class="header-anchor" href="#_1-integration-bugs-as-signal" aria-label="Permalink to &quot;1. Integration Bugs as Signal&quot;">​</a></h3><p>Two silent failures invisible to pass rates, caught by telemetry:</p><ul><li><code>reflections_written=80, reflections_retrieved=0</code> → container non-persistence</li><li><code>PASTE_invocations=0</code> → feature never activated</li></ul><p>&quot;Observability doubles as a bug-detector for the engineering loop.&quot;</p><h3 id="_2-acon-cache-coupling" tabindex="-1">2. ACON-Cache Coupling <a class="header-anchor" href="#_2-acon-cache-coupling" aria-label="Permalink to &quot;2. ACON-Cache Coupling&quot;">​</a></h3><p>Observation-compression gate stored compressed summaries in cache instead of raw outputs → corrupted downstream reads. An architectural invariant violation only visible via telemetry.</p><h3 id="_3-model-dependent-feature-interactions" tabindex="-1">3. Model-Dependent Feature Interactions <a class="header-anchor" href="#_3-model-dependent-feature-interactions" aria-label="Permalink to &quot;3. Model-Dependent Feature Interactions&quot;">​</a></h3><p>Self-evaluation helps stronger models (Claude Sonnet) but hurts weaker ones (gpt-5.4-nano). Feature interactions depend on latent model capability.</p><h3 id="_4-sparsity-in-practice" tabindex="-1">4. Sparsity in Practice <a class="header-anchor" href="#_4-sparsity-in-practice" aria-label="Permalink to &quot;4. Sparsity in Practice&quot;">​</a></h3><p>SAAS prior discovered only ~5 of ~40 nominal dimensions carry signal — structural lesson: <strong>flag-space composition dominates per-flag tuning</strong>.</p><hr><h2 id="discussion" tabindex="-1">Discussion <a class="header-anchor" href="#discussion" aria-label="Permalink to &quot;Discussion&quot;">​</a></h2><p><strong>AHO scope</strong>: Runs once per (agent, task-suite, model) epoch—not continuously. Amortizes meta-learned posteriors across related configurations.</p><p><strong>Prerequisite</strong>: Structured telemetry with read/write counters is required for the bug-detection loop that manual ablation misses.</p><p><strong>Task-agnostic</strong>: Formulation applicable to any agent harness with bounded configuration space and reproducible task suites.</p><hr><h2 id="conclusion" tabindex="-1">Conclusion <a class="header-anchor" href="#conclusion" aria-label="Permalink to &quot;Conclusion&quot;">​</a></h2><p>Harness engineering has matured from a systems problem into a <strong>hyperparameter optimization problem</strong> requiring principled automation. Manual stacking of published techniques produced diminishing returns; HARBOR&#39;s automated Bayesian optimizer with safety constraints recovered the manual peak from 2 flags instead of 8, while identifying integration bugs the manual loop missed across four rounds.</p><hr><h2 id="workspace-relevance" tabindex="-1">Workspace Relevance <a class="header-anchor" href="#workspace-relevance" aria-label="Permalink to &quot;Workspace Relevance&quot;">​</a></h2><p>Complements <code>harness-meta</code> skill&#39;s Harness Audit (static gap analysis + CAR framework) with a principled <strong>search algorithm</strong> for configuration optimization once gaps are identified. The Ratchet principle in <code>harness-meta</code> is the manual version of HARBOR&#39;s automated loop.</p><p>HARBOR&#39;s safety constraint (posterior chance constraint) is directly analogous to <code>autoresearch</code>&#39;s Guard: discard changes whose lower bound violates the safety margin.</p>`,64)])])}const m=a(o,[["render",s]]);export{h as __pageData,m as default};
